VALUES
  ('social-worker-moex-06260', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在設計問卷時，研究者應該儘量避免題目使受試者產生誤解。下列對於問卷設計應該注意事項的敘述， 何者錯誤？', '["避免語意模糊、混淆", "一題二問方能使問卷控制在受試者可以接受的長度", "引導式問題應該儘量避免", "不要設計受訪者專業度無法回答的問題"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "5cc1330cfca7", "answer_pdf_sha1": "9dfdf14e60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06261', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在質性研究中，研究者常常運用三角測定（triangulation）來加強研究之品質。下列何者不是三角測定方 法的類型：', '["資料三角測定", "研究者三角測定", "理論三角測定", "變項三角測定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "5cc1330cfca7", "answer_pdf_sha1": "9dfdf14e60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06262', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '問卷填答者常常不考慮個別題目的真實性，就做出同意或不同意的作答，我們稱之為：', '["社會期望性（social desirability）", "回答固著（response set）", "不決斷性（indecisiveness）", "偽裝（dissimulation）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "5cc1330cfca7", "answer_pdf_sha1": "9dfdf14e60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06263', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列關於紮根理論（grounded theory）的敘述，何者錯誤？', '["試圖從觀察資料中所發現的模式、主題與類別中推展出理論", "研究時保持比較的態度、擁有多元觀點、定期回頭檢視與質問、保持懷疑的態度", "它是一個從上往下的演繹過程", "不斷在資料、理論及彼此之間持續比較，而理論飽和（theoretical saturated）是它的終點"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "5cc1330cfca7", "answer_pdf_sha1": "9dfdf14e60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06264', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '小華閱讀一篇有關家庭暴力的研究報告，報告中指出，家庭平均年收入較低的地區，離婚率較高。由此 小華可以推論出何者？', '["貧賤夫妻百事哀", "該地區家庭平均年收入與其離婚率呈負相關", "年收入高家庭生活比較幸福", "低收入家庭容易發生暴力行為，而暴力行為往往導致離婚"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "5cc1330cfca7", "answer_pdf_sha1": "9dfdf14e60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06265', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '臺灣每10年進行一次人口及住宅普查（census），請問這是屬於何種調查法？', '["內容分析研究（content analysis）", "橫斷面研究（cross-sectional study）", "同組研究（panel study）", "非典型調查法（non-typical survey）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "5cc1330cfca7", "answer_pdf_sha1": "9dfdf14e60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 21, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06266', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '曉華負責弱勢家庭兒童課後輔導方案成效評估，她要了解學童在輔導課程中完成家庭作業的比率，她在 每週五課輔時間結束前，以口頭詢問「這個星期每天都有完成家庭作業的人請舉手」，再以學童舉手人 數來計算完成家庭作業人數。請問這個方法會出現何種測量上的誤差？', '["隨機誤差（random error）", "交互信度誤差（interrater reliability error）", "測量方式不一致（unconsistency measurement）", "社會期望性偏誤（social desirability bias）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "5cc1330cfca7", "answer_pdf_sha1": "9dfdf14e60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06267', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '續上題，經由督導提醒之後，曉華決定向學童的家長發放問卷調查，其中一題是：「請問您及您的配偶', '["從不檢查", "傍晚孩子放學後到睡覺前", "孩子睡覺後", "早上 孩子上學前」請問，這一題犯了那一個建構問卷原則的錯誤？"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "5cc1330cfca7", "answer_pdf_sha1": "9dfdf14e60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 23, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06268', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有愈來愈多人傾向運用網路問卷進行線上調查（online surveys），小惠想要了解民眾自行付費使用居家服 務的意願，她在個人臉書（facebook）發布這個調查訊息，並提供問卷超連結網址，7 天之後共得到 510 份回覆。請問此調查方法相對於其他社會調查方法的優點，不包括何者？', '["具代表性", "成本相對較低", "快速回覆", "調查樣本可以很大"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "5cc1330cfca7", "answer_pdf_sha1": "9dfdf14e60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06269', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '卡方獨立性檢定對樣本的大小非常敏感。試問，當交叉表各欄位的觀察值都變成原來的10倍時，則樣本 卡方值為原來的幾倍？', '["1/10倍", "2倍", "10倍", "100倍"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "5cc1330cfca7", "answer_pdf_sha1": "9dfdf14e60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
